"""
find_collision.py

寻找与 Java 字符串 "ISCC2025" 具有相同 hashCode() 但字符串不同的碰撞。

思路：使用 Java String.hashCode 实现（h = 31*h + c，32-bit 溢出），对目标长度做分割（left+right），
使用 meet-in-the-middle：预计算所有右半部分的 hash 映射，然后遍历左半部分查找所需的右半部分。

字符集：大写字母 + 数字（与目标字符串字符类别一致）。

运行：
    python find_collision.py

注意：脚本在找到第一个不同于目标字符串的碰撞后退出并打印验证结果。
"""

from itertools import product
import string

MASK32 = 0xFFFFFFFF

def java_hash(s: str) -> int:
    h = 0
    for ch in s:
        h = (31 * h + ord(ch)) & MASK32
    return h

def find_collision(target: str, alphabet: str, len_left: int, len_right: int):
    """Meet-in-the-middle for lengths len_left + len_right. Return candidate or None."""
    target_hash = java_hash(target)
    pow31_len_right = pow(31, len_right, 1 << 32)

    # build map for right parts: hash(R) -> R
    right_map = {}
    total_right = len(alphabet) ** len_right
    print(f"Building right map (size={total_right}) for len_right={len_right}...")
    cnt = 0
    for tup in product(alphabet, repeat=len_right):
        s = ''.join(tup)
        h = java_hash(s)
        # store first seen for this hash
        if h not in right_map:
            right_map[h] = s
        cnt += 1
        if cnt % 200000 == 0:
            print(f"  processed {cnt}/{total_right} right combos")

    print("Searching left parts...")
    total_left = len(alphabet) ** len_left
    cnt = 0
    for tup in product(alphabet, repeat=len_left):
        left = ''.join(tup)
        left_h = java_hash(left)
        left_contrib = (left_h * pow31_len_right) & MASK32
        need = (target_hash - left_contrib) & MASK32
        if need in right_map:
            candidate = left + right_map[need]
            if candidate != target:
                return candidate
        cnt += 1
        if cnt % 200000 == 0:
            print(f"  checked {cnt}/{total_left} left combos")

    return None

def main():
    target = "ISCC2025"
    print(f"Target: {target}")
    t_hash = java_hash(target)
    # For display, compute signed int equivalent like Java
    signed = t_hash if t_hash < (1 << 31) else t_hash - (1 << 32)
    print(f"Target java_hash (unsigned 32-bit): {t_hash}, signed: {signed}")

    alphabet = string.ascii_uppercase + string.digits  # A-Z0-9

    # Try a few split lengths (len_left + len_right). Start with 4+4 which is ~1.68M per side.
    attempts = [(4,4), (3,3), (2,2), (5,5)]
    for len_left, len_right in attempts:
        # skip huge sizes: limit each side to ~3M entries to avoid memory explosion
        if len(alphabet) ** len_left > 4_000_000 or len(alphabet) ** len_right > 4_000_000:
            print(f"Skipping {len_left}+{len_right} because side too large")
            continue
        print(f"Trying split {len_left}+{len_right} with alphabet size {len(alphabet)}")
        cand = find_collision(target, alphabet, len_left, len_right)
        if cand:
            print("Found candidate:", cand)
            print("Verify:")
            print("  equal hash?", java_hash(cand) == t_hash)
            print("  equal string?", cand == target)
            return

    print("No collision found with attempted splits. Try increasing lengths or expanding alphabet.")

if __name__ == '__main__':
    main()





